/**
 * Calculates the Community Support Network Strength Score.
 * @param {object} inputs - The input values from the calculator.
 * @param {number} inputs.volunteerRate - Active volunteers per 1,000 residents (0-200).
 * @param {number} inputs.resourceShareIndex - Households participating in resource sharing (0-100%).
 * @param {number} inputs.mentalHealthServiceAccessScore - Mental Health Service Accessibility (1-5).
 * @param {number} inputs.neighborConnectionPercentage - Residents knowing >=5 neighbors for help (0-100%).
 * @param {number} inputs.formalNetworkDensity - Formal Support Organizations per 10,000 residents (0-20).
 * @param {number} inputs.crisisCommunicationEffectiveness - Crisis Communication Effectiveness (1-5).
 * @param {number} inputs.communityTrainingParticipation - Annual Community Preparedness Training Participation (0-50%).
 * @param {number} inputs.vulnerablePopulationCoverage - Vulnerable Population Targeted Support Coverage (0-100%).
 * @returns {object} An object containing communityStrengthScore, resilienceCategory, and keyAreaForImprovement.
 */

const { volunteerRate, resourceShareIndex, mentalHealthServiceAccessScore, 
  neighborConnectionPercentage, formalNetworkDensity, 
  crisisCommunicationEffectiveness, communityTrainingParticipation, 
  vulnerablePopulationCoverage } = inputs;

// --- Input Normalization (0-1 scale) ---
// Max values chosen to represent excellent performance, not necessarily theoretical maximums.
const normalizedInputs = {
  volunteerRate: Math.min(Math.max(volunteerRate, 0), 200) / 200, // Cap at 200 for normalization
  resourceShareIndex: Math.min(Math.max(resourceShareIndex, 0), 100) / 100,
  mentalHealthServiceAccessScore: (Math.min(Math.max(mentalHealthServiceAccessScore, 1), 5) - 1) / 4,
  neighborConnectionPercentage: Math.min(Math.max(neighborConnectionPercentage, 0), 100) / 100,
  formalNetworkDensity: Math.min(Math.max(formalNetworkDensity, 0), 20) / 20, // Cap at 20 for normalization
  crisisCommunicationEffectiveness: (Math.min(Math.max(crisisCommunicationEffectiveness, 1), 5) - 1) / 4,
  communityTrainingParticipation: Math.min(Math.max(communityTrainingParticipation, 0), 50) / 50, // Cap at 50% for realistic max impact
  vulnerablePopulationCoverage: Math.min(Math.max(vulnerablePopulationCoverage, 0), 100) / 100
};

// --- Weights for each factor (sum of weights = 11.0) ---
const weights = {
  volunteerRate: 1.5,
  resourceShareIndex: 1.2,
  mentalHealthServiceAccessScore: 2.0, // High importance
  neighborConnectionPercentage: 1.8, // High importance
  formalNetworkDensity: 1.0,
  crisisCommunicationEffectiveness: 1.5,
  communityTrainingParticipation: 0.8,
  vulnerablePopulationCoverage: 1.2
};

const totalWeight = Object.values(weights).reduce((sum, w) => sum + w, 0);

// --- Calculate Weighted Sum ---
let weightedSum = 0;
let lowestNormalizedScore = Infinity;
let keyAreaId = '';

for (const key in normalizedInputs) {
  if (normalizedInputs.hasOwnProperty(key)) {
    const normalizedValue = normalizedInputs[key];
    weightedSum += normalizedValue * weights[key];

    // Identify the key area for improvement based on normalized (raw) score
    if (normalizedValue < lowestNormalizedScore) {
      lowestNormalizedScore = normalizedValue;
      keyAreaId = key;
    }
  }
}

// --- Map keyAreaId to a user-friendly label ---
const inputLabels = {
  volunteerRate: 'Volunteer Engagement',
  resourceShareIndex: 'Resource Sharing Initiatives',
  mentalHealthServiceAccessScore: 'Mental Health Service Accessibility',
  neighborConnectionPercentage: 'Informal Neighbor Connections',
  formalNetworkDensity: 'Formal Support Organization Density',
  crisisCommunicationEffectiveness: 'Crisis Communication Effectiveness',
  communityTrainingParticipation: 'Community Preparedness Training',
  vulnerablePopulationCoverage: 'Vulnerable Population Support'
};

const keyAreaForImprovement = inputLabels[keyAreaId] || 'Overall Network Strength';

// --- Scale to 0-100 ---
const communityStrengthScore = (weightedSum / totalWeight) * 100;

// --- Determine Resilience Category ---
let resilienceCategory;
if (communityStrengthScore <= 25) {
  resilienceCategory = 'Nascent';
} else if (communityStrengthScore <= 50) {
  resilienceCategory = 'Developing';
} else if (communityStrengthScore <= 75) {
  resilienceCategory = 'Established';
} else {
  resilienceCategory = 'Thriving';
}

return {
  communityStrengthScore: parseFloat(communityStrengthScore.toFixed(1)),
  resilienceCategory: resilienceCategory,
  keyAreaForImprovement: keyAreaForImprovement
};
